#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <stdbool.h>

bool is_palindrome(const char *s){
    int len = strlen(s);
    char filtered[1005];
    int flen = 0;
    for(int i=0;i<len;i++){
        if(isalnum((unsigned char)s[i]))
            filtered[flen++] = tolower((unsigned char)s[i]);
    }
    char stack[1005];
    int top = -1;
    for(int i=0;i<flen;i++)
        stack[++top] = filtered[i];
    for(int i=0;i<flen;i++){
        if(stack[top--] != filtered[i])
            return false;
    }
    return true;
}

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume newline after T
    char line[1005];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line, sizeof(line), stdin)) line[0]='\0';
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        if(is_palindrome(line))
            printf("Palindrome\n");
        else
            printf("Not palindrome\n");
    }
    return 0;
}

