#include <bits/stdc++.h>
using namespace std;

bool isPalindrome(const string &s){
    string filtered;
    filtered.reserve(s.size());
    for(char ch: s){
        if(isalnum(static_cast<unsigned char>(ch)))
            filtered.push_back(tolower(static_cast<unsigned char>(ch)));
    }
    vector<char> st(filtered.begin(), filtered.end());
    for(char ch: filtered){
        if(st.back()!=ch) return false;
        st.pop_back();
    }
    return true;
}

int main(){
