const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').split('\n');
let idx = 0;
const T = parseInt((lines[idx++]||'').trim(),10);
function isPalindrome(str){
    const filtered = [];
    for(const ch of str){
        if(/[a-zA-Z0-9]/.test(ch)) filtered.push(ch.toLowerCase());
    }
    const stack = filtered.slice();
    for(const ch of filtered){
        if(stack.pop() !== ch) return false;
    }
    return true;
}
let out = [];
for(let t=0; t<T; t++){
    const s = lines[idx++] ?? '';
    out.push(isPalindrome(s) ? 'Palindrome' : 'Not palindrome');
}
